import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box, Select, MenuItem, Checkbox } from '@material-ui/core';

export default function SaleManagement() {
  const [sales, setSales] = useState([]);
  const [items, setItems] = useState([]);
  const [companies, setCompanies] = useState([]);
  const [newSale, setNewSale] = useState({ item: { id: '' }, quantity: 0, price: 0, isWholesale: false, company: { id: '' } });

  useEffect(() => {
    axios.get('http://localhost:8080/api/sales').then(res => setSales(res.data));
    axios.get('http://localhost:8080/api/items').then(res => setItems(res.data));
    axios.get('http://localhost:8080/api/companies').then(res => setCompanies(res.data));
  }, []);

  const addSale = () => {
    axios.post('http://localhost:8080/api/sales', newSale).then(res => {
      setSales([...sales, res.data]);
      setNewSale({ item: { id: '' }, quantity: 0, price: 0, isWholesale: false, company: { id: '' } });
    });
  };

  return (
    <div>
      <Box marginBottom={2}>
        <Select
          value={newSale.item.id}
          onChange={e => setNewSale({ ...newSale, item: { id: e.target.value } })}
        >
          {items.map(item => (
            <MenuItem key={item.id} value={item.id}>{item.name}</MenuItem>
          ))}
        </Select>
        <TextField
          label="Quantity"
          type="number"
          value={newSale.quantity}
          onChange={e => setNewSale({ ...newSale, quantity: parseInt(e.target.value) })}
        />
        <TextField
          label="Price"
          type="number"
          value={newSale.price}
          onChange={e => setNewSale({ ...newSale, price: parseFloat(e.target.value) })}
        />
        <Checkbox
          checked={newSale.isWholesale}
          onChange={e => setNewSale({ ...newSale, isWholesale: e.target.checked })}
          label="Wholesale"
        />
        <Select
          value={newSale.company.id}
          onChange={e => setNewSale({ ...newSale, company: { id: e.target.value } })}
        >
          {companies.map(company => (
            <MenuItem key={company.id} value={company.id}>{company.name}</MenuItem>
          ))}
        </Select>
        <Button onClick={addSale} color="primary" variant="contained">Add Sale</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Item</TableCell>
            <TableCell>Quantity</TableCell>
            <TableCell>Price</TableCell>
            <TableCell>Wholesale</TableCell>
            <TableCell>Company</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {sales.map(sale => (
            <TableRow key={sale.id}>
              <TableCell>{sale.item.name}</TableCell>
              <TableCell>{sale.quantity}</TableCell>
              <TableCell>{sale.price}</TableCell>
              <TableCell>{sale.isWholesale ? 'Yes' : 'No'}</TableCell>
              <TableCell>{sale.company.name}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
